        /**
         * Completes all achievements
         */
        async function completeAllAchievements() {
            if (DEBUG) console.debug('[Preset] completeAllAchievements: Starting to complete all achievements');

            const data = getYamlDataFromTextarea();
            if (!data || typeof data === 'string') {
                if (DEBUG) console.warn('[Preset] completeAllAchievements: This preset requires YAML parsing.');
                showSaveStatus('save-preset-status', '⚠️ This preset requires YAML parsing. Please ensure js-yaml is loaded.', false);
                return;
            }

            // Ensure stats.achievements exists
            if (!data.stats) data.stats = {};
            if (!data.stats.achievements) data.stats.achievements = {};

            const achievementCounters = {
                '00_level_10': 1,
                '01_level_30': 1,
                '02_level_50': 1,
                '03_uvh_5': 1,
                '04_cosmetics_collect': 60,
                '05_vehicles_collect': 10,
                '06_legendaries_equip': 1,
                '07_challenges_gear': 1,
                '08_challenges_manufacturer': 1,
                // complete all activities achievement doesnt seem to have a counter - it just checks completed activity missions
                '10_worldevents_colosseum': 1,
                '11_worldevents_airship': 1,
                '12_worldevents_meteor': 1,
                '13_contracts_complete': 80,
                '14_discovery_grasslands': 54,
                '15_discovery_mountains': 62,
                '16_discovery_shatteredlands': 47,
                '17_discovery_city': 21,
                '18_worldboss_defeat': 1,
                '19_vaultguardian_defeat': {
                    '19_vaultguardian_grasslands': 1,
                    '19_vaultguardian_mountains': 1,
                    '19_vaultguardian_shatteredlands': 1,
                },
                '20_missions_survivalist': 3,
                '21_missions_auger': 7,
                '22_missions_electi': 3,
                '23_missions_claptrap': 5,
                '24_missions_side': 98,
                '25_missions_grasslands': 1,
                '26_missions_mountains': 1,
                '27_missions_shatteredlands': 1,
                '28_missions_elpis': 1,
                '29_missions_main': 1,
                '30_moxxi_hidden': 1,
                '31_tannis_hidden': 1,
                '32_zane_hidden': 1,
                '33_oddman_hidden': 1,
                '34_dave_hidden': 1,
            };

            // Apply achievement counters - always set them (don't check if higher like challenges)
            for (const [key, value] of Object.entries(achievementCounters)) {
                // Handle nested objects (e.g., 19_vaultguardian_defeat)
                if (typeof value === 'object' && value !== null && !Array.isArray(value)) {
                    data.stats.achievements[key] = data.stats.achievements[key] || {};
                    for (const [nestedKey, nestedValue] of Object.entries(value)) {
                        data.stats.achievements[key][nestedKey] = nestedValue;
                    }
                } else {
                    data.stats.achievements[key] = value;
                }
            }

            applyNexusAchievementListChallengesToData(data);

            // Also complete all activities (zone activity missionsets)
            // This is needed for the "complete all activities" achievement
            // The achievement checks if all zone activity missions are completed
            // This matches the reference implementation: mergeMissionsetsWithPrefix('missionset_zoneactivity_')
            if (!data.missions) data.missions = {};
            if (!data.missions.local_sets) data.missions.local_sets = {};
            
            // Try to load and merge mission data for zone activities
            let missionData = null;
            try {
                const rawAch = await getMissionTemplateDataForMerge();
                missionData =
                    rawAch && typeof rawAch === 'object' ? JSON.parse(JSON.stringify(rawAch)) : null;
                if (missionData) augmentMissionTemplatesWithNexusStubs(missionData);
                if (missionData && typeof missionData === 'object') {
                    if (DEBUG) console.debug('[Preset] completeAllAchievements: Mission data loaded, merging zone activity missionsets');
                    mergeMissionsetsWithPrefix(data, 'missionset_zoneactivity_', missionData);
                } else if (typeof window.MISSIONSETS !== 'undefined' && window.MISSIONSETS) {
                    if (DEBUG) console.debug('[Preset] completeAllAchievements: Using window.MISSIONSETS for zone activity missionsets');
                    mergeMissionsetsWithPrefix(data, 'missionset_zoneactivity_', window.MISSIONSETS);
                } else {
                    if (DEBUG) console.warn('[Preset] completeAllAchievements: Cannot populate zone activity missionsets - mission data not available');
                }
            } catch (err) {
                if (DEBUG) console.error('[Preset] completeAllAchievements: Error loading mission data:', err);
            }

            applyNexusRememberedFinalsToLocalSets(data);

            setYamlDataToTextarea(data, {
                showChanges: true,
                searchText: '01_level_30',
                fallbackSearchText: 'achievements',
                message: 'Completing all achievements...',
                successMessage: '✅ All achievements completed!'
            });

            if (DEBUG) console.debug('[Preset] completeAllAchievements: All achievements completed');
        }

        /**
         * Completes all story missions
         */
        /**
         * Cowbell DLC (templates: missionset_dlc_banjo) open-world flags: portals, speakeasy doors,
         * stats.regions.cowbell_speakeasy, and gbx_discovery_pc.pins_state.metrics.hasseenregionlist.
         */
        const COWBELL_SPEAKEASY_PORTAL_STATS = {
            speakeasyportal_1: 1,
            speakeasyportal_4: 1,
            speakeasyportal_5: 1,
            speakeasyportal_6: 1,
        };

        const COWBELL_SPEAKEASY_DOOR_STATS = {
            speakeasydoor_1: 1,
            speakeasydoor_2: 1,
            speakeasydoor_3: 1,
        };

        const COWBELL_SEEN_REGION_SPEAKEASY = 'Cowbell_Speakeasy';

        function mergedSetKeysTouchCowbellOpenworld(mergedKeys) {
            if (!mergedKeys || !mergedKeys.length) return false;
            for (let i = 0; i < mergedKeys.length; i++) {
                const k = String(mergedKeys[i] || '').toLowerCase();
                if (k.indexOf('cowbell') !== -1 || k.indexOf('banjo') !== -1) return true;
            }
            return false;
        }

        /**
         * missions.local_sets keys for Cowbell DLC (may use main/side/micro or missionset_cowbell_* naming).
         */
        function missionSetKeyIsCowbellDlcContent(k) {
            const s = String(k || '').toLowerCase();
            if (!s.startsWith('missionset_')) return false;
            if (
                s === 'missionset_main_cowbell' ||
                s === 'missionset_main_cowbell_unlock' ||
                s === 'missionset_side_cowbell' ||
                s === 'missionset_micro_cowbell' ||
                s === 'missionset_cowbell_activity_speakeasyportal'
            ) {
                return true;
            }
            if (s.startsWith('missionset_dlc_') && s.indexOf('banjo') !== -1) return true;
            return s.indexOf('cowbell') !== -1;
        }

        function applyCowbellSpeakeasyPortalOpenworldStats(data) {
            if (!data || typeof data === 'string') return;
            if (!data.stats) data.stats = {};
            if (!data.stats.cowbell_openworld) data.stats.cowbell_openworld = {};
            const ow = data.stats.cowbell_openworld;
            if (!ow.cowbell_activities) ow.cowbell_activities = {};
            if (!ow.cowbell_activities.speakeasyportals) ow.cowbell_activities.speakeasyportals = {};
            Object.assign(ow.cowbell_activities.speakeasyportals, COWBELL_SPEAKEASY_PORTAL_STATS);

            if (!ow.cowbell_misc) ow.cowbell_misc = {};
            if (!ow.cowbell_misc.speakeasydoors) ow.cowbell_misc.speakeasydoors = {};
            Object.assign(ow.cowbell_misc.speakeasydoors, COWBELL_SPEAKEASY_DOOR_STATS);

            if (!data.stats.regions) data.stats.regions = {};
            data.stats.regions.cowbell_speakeasy = Object.assign(
                {},
                data.stats.regions.cowbell_speakeasy || {},
                { discovered: 1 }
            );

            if (!data.gbx_discovery_pc) data.gbx_discovery_pc = {};
            if (!data.gbx_discovery_pc.pins_state) data.gbx_discovery_pc.pins_state = {};
            if (!data.gbx_discovery_pc.pins_state.metrics) data.gbx_discovery_pc.pins_state.metrics = {};
            const metrics = data.gbx_discovery_pc.pins_state.metrics;
            let regionSeen = metrics.hasseenregionlist;
            if (!Array.isArray(regionSeen)) regionSeen = [];
            if (regionSeen.indexOf(COWBELL_SEEN_REGION_SPEAKEASY) === -1) {
                regionSeen.push(COWBELL_SEEN_REGION_SPEAKEASY);
            }
            metrics.hasseenregionlist = regionSeen;
        }

        /**
         * After template merge, overlay mission.final + ui_flags from Legit Builder Nexus ingest
         * (rememberedFinals on window.NEXUS_MISSION_MANIFEST), matching in-game completed saves.
         */
        function applyNexusRememberedFinalsToLocalSets(data) {
            const nexus =
                typeof window !== 'undefined' &&
                window.NEXUS_MISSION_MANIFEST &&
                typeof window.NEXUS_MISSION_MANIFEST === 'object'
                    ? window.NEXUS_MISSION_MANIFEST
                    : null;
            if (!nexus || !data || typeof data !== 'object' || typeof data === 'string') return;
            if (!data.missions || !data.missions.local_sets || typeof data.missions.local_sets !== 'object') return;
            const ls = data.missions.local_sets;
            const setKeys = Object.keys(ls);
            for (let si = 0; si < setKeys.length; si++) {
                const sk = setKeys[si];
                const nSet = nexus[sk];
                if (!nSet || !nSet.missions || typeof nSet.missions !== 'object') continue;
                const setNode = ls[sk];
                if (!setNode || typeof setNode !== 'object' || !setNode.missions || typeof setNode.missions !== 'object') {
                    continue;
                }
                const mKeys = Object.keys(setNode.missions);
                for (let mj = 0; mj < mKeys.length; mj++) {
                    const mk = mKeys[mj];
                    const nMission = nSet.missions[mk];
                    if (!nMission || typeof nMission !== 'object') continue;
                    const rf = nMission.rememberedFinals;
                    if (!rf || typeof rf !== 'object' || !Object.keys(rf).length) continue;
                    const m = setNode.missions[mk];
                    if (!m || typeof m !== 'object') continue;
                    const slo = String(m.status || '').toLowerCase();
                    if (!slo.includes('completed')) continue;
                    if (!m.final || typeof m.final !== 'object') m.final = {};
                    Object.assign(m.final, rf);
                    m.ui_flags = 1;
                }
            }
        }

        /**
         * Merges mission sets with a specific prefix from mission data into the save data object.
         * @param {Object} data - The save data object to merge into
         * @param {string} prefix - The prefix of the missionset key to merge (e.g., 'missionset_main_')
         * @param {Object} missionData - The mission data object containing all mission sets
         * @returns {string[]} Keys merged into local_sets (empty if none)
         */
        function mergeMissionsetsWithPrefix(data, prefix, missionData) {
            if (!missionData || typeof missionData !== 'object') {
                if (DEBUG) console.warn(`[Preset] mergeMissionsetsWithPrefix: No mission data provided for prefix: ${prefix}`);
                return [];
            }

            if (!data || typeof data === 'string') {
                if (DEBUG) console.warn('[Preset] mergeMissionsetsWithPrefix: Invalid data object.');
                return [];
            }

            if (!data.missions) data.missions = {};
            if (!data.missions.local_sets) data.missions.local_sets = {};

            // Filter mission sets by prefix
            const filteredMissionsets = {};
            for (const key in missionData) {
                if (key.startsWith(prefix)) {
                    filteredMissionsets[key] = missionData[key];
                }
            }

            const foundKeys = Object.keys(filteredMissionsets);
            if (foundKeys.length === 0) {
                if (DEBUG) console.warn(`[Preset] mergeMissionsetsWithPrefix: No missionsets found with prefix: ${prefix}`);
                return [];
            }

            if (DEBUG) console.debug(`[Preset] Merging ${foundKeys.length} missionset(s) with prefix "${prefix}"`);

            // Merge mission sets into save data (deep copy to avoid reference issues)
            const target = data.missions.local_sets;
            for (const key in filteredMissionsets) {
                target[key] = JSON.parse(JSON.stringify(filteredMissionsets[key]));
            }
            return foundKeys;
        }

        /**
         * Loads mission data from missions.yaml file
         * @returns {Promise<Object|null>} The parsed mission data or null if loading fails
         */
        async function loadMissionData() {
            // First, check if MISSIONSETS is already loaded globally
            if (typeof window.MISSIONSETS !== 'undefined' && window.MISSIONSETS) {
                if (DEBUG) console.debug('[Preset] MISSIONSETS already loaded from cache');
                return window.MISSIONSETS;
            }
            
            // Try to load from embedded compressed data first (for offline use)
            // This is the compressed MISSIONSETS data from bl4-save-tools-main
            const MISSIONSETS_COMPRESSED = '';
            
            try {
                if (DEBUG) console.debug('[Preset] Decompressing embedded MISSIONSETS data...');
                const compressedBytes = Uint8Array.from(atob(MISSIONSETS_COMPRESSED), c => c.charCodeAt(0));
                if (DEBUG) console.debug('[Preset] MISSIONSETS compressed bytes length:', compressedBytes.length);
                
                // Use pako to decompress (same as collectibles)
                const decompressed = pako.inflate(compressedBytes, { to: 'string' });
                if (DEBUG) console.debug('[Preset] MISSIONSETS decompressed length:', decompressed.length);
                const MISSIONSETS_DATA = jsyaml.load(decompressed);
                if (DEBUG) console.debug('[Preset] MISSIONSETS_DATA loaded, missionsets:', Object.keys(MISSIONSETS_DATA || {}).length);
                // Cache it globally for future use
                window.MISSIONSETS = MISSIONSETS_DATA;
                return MISSIONSETS_DATA;
            } catch (e) {
                if (DEBUG) console.debug('[Preset] Failed to decompress embedded MISSIONSETS, trying file/URL fallback:', e.message);
            }
            
            // In Electron, try to read from local file system first
            if (typeof window !== 'undefined' && window.IS_ELECTRON_APP && window.electronAPI) {
                try {
                    const appPath = window.electronAPI.getAppPath();
                    const resourcesPath = window.electronAPI.getResourcesPath();
                    
                    if (appPath || resourcesPath) {
                        // Construct paths as strings (can't use require('path') in renderer)
                        // Try multiple possible paths for missions.yaml
                        const pathSeparator = (appPath && appPath.includes('\\')) || (resourcesPath && resourcesPath.includes('\\')) ? '\\' : '/'; // Windows vs Unix
                        const possiblePaths = [];
                        
                        // Try unpacked location first (most likely for packaged apps)
                        if (resourcesPath) {
                            possiblePaths.push(
                                resourcesPath + pathSeparator + 'app.asar.unpacked' + pathSeparator + 'bl4-save-tools-main' + pathSeparator + 'data' + pathSeparator + 'missions.yaml'
                            );
                        }
                        
                        // Try relative to app path (development mode)
                        if (appPath) {
                            possiblePaths.push(
                                appPath + pathSeparator + 'bl4-save-tools-main' + pathSeparator + 'data' + pathSeparator + 'missions.yaml',
                                appPath + pathSeparator + '..' + pathSeparator + 'bl4-save-tools-main' + pathSeparator + 'data' + pathSeparator + 'missions.yaml'
                            );
                        }
                        
                        for (const filePath of possiblePaths) {
                            if (window.electronAPI.fileExists(filePath)) {
                                const yamlText = window.electronAPI.readFile(filePath);
                                if (yamlText && typeof jsyaml !== 'undefined') {
                                    if (DEBUG) console.debug(`[Preset] Successfully loaded missions.yaml from local file: ${filePath}`);
                                    return jsyaml.load(yamlText);
                                }
                            }
                        }
                    }
                } catch (error) {
                    if (DEBUG) console.debug(`[Preset] Failed to load missions.yaml from Electron file system:`, error.message);
                }
            }
            
            // Fallback to fetch (for browser or if Electron file read failed)
            const isFileProtocol = window.location.protocol === 'file:';
            const paths = isFileProtocol ? [
                'https://save-editor.be/bl4-save-tools-main/data/missions.yaml'
            ] : [
                'https://save-editor.be/bl4-save-tools-main/data/missions.yaml',
                '/bl4-save-tools-main/data/missions.yaml',
                '../bl4-save-tools-main/data/missions.yaml',
                'bl4-save-tools-main/data/missions.yaml'
            ];
            
            for (const missionYamlPath of paths) {
                try {
                    const response = await fetch(missionYamlPath);
                    if (response.ok) {
                        const yamlText = await response.text();
                        if (typeof jsyaml !== 'undefined') {
                            if (DEBUG) console.debug(`[Preset] Successfully loaded missions.yaml from: ${missionYamlPath}`);
                            return jsyaml.load(yamlText);
                        }
                    }
                } catch (error) {
                    // Try next path
                    if (DEBUG) console.debug(`[Preset] Failed to load from ${missionYamlPath}:`, error.message);
                    continue;
                }
            }
            
            if (DEBUG) console.warn('[Preset] Could not load missions.yaml from any path');
            return null;
        }

        /**
         * Prefer fresh hosted missions.yaml for bulk complete (includes newer DLC missionsets), then fall back to loadMissionData().
         */
        async function getMissionTemplateDataForMerge() {
            const tryUrls = [
                'https://save-editor.be/bl4-save-tools-main/data/missions.yaml',
            ];
            for (let ui = 0; ui < tryUrls.length; ui++) {
                try {
                    const response = await fetch(tryUrls[ui] + '?cb=' + Date.now(), { cache: 'no-store' });
                    if (response.ok) {
                        const yamlText = await response.text();
                        if (typeof jsyaml !== 'undefined' && yamlText) {
                            const obj = jsyaml.load(yamlText);
                            if (obj && typeof obj === 'object') {
                                const nSets = Object.keys(obj).filter((k) => k.startsWith('missionset_')).length;
                                if (nSets >= 30) {
                                    window.MISSIONSETS = obj;
                                    if (DEBUG) {
                                        console.debug(
                                            '[Preset] getMissionTemplateDataForMerge: using network missions.yaml, missionsets:',
                                            nSets
                                        );
                                    }
                                    return obj;
                                }
                            }
                        }
                    }
                } catch (err) {
                    if (DEBUG) console.debug('[Preset] getMissionTemplateDataForMerge: fetch failed', err && err.message);
                }
            }
            return loadMissionData();
        }

        /**
         * Add minimal completed stubs for missionsets present in Nexus manifest but missing from template (e.g. new DLC).
         */
        function augmentMissionTemplatesWithNexusStubs(missionData) {
            if (!missionData || typeof missionData !== 'object') return missionData;
            const nexus =
                typeof window !== 'undefined' && window.NEXUS_MISSION_MANIFEST && typeof window.NEXUS_MISSION_MANIFEST === 'object'
                    ? window.NEXUS_MISSION_MANIFEST
                    : null;
            if (!nexus) return missionData;
            const keys = Object.keys(nexus);
            for (let i = 0; i < keys.length; i++) {
                const setKey = keys[i];
                if (typeof setKey !== 'string' || !setKey.startsWith('missionset_')) continue;
                if (missionData[setKey]) continue;
                const setNode = nexus[setKey];
                const missionsBlock = setNode && setNode.missions && typeof setNode.missions === 'object' ? setNode.missions : null;
                if (!missionsBlock) continue;
                const mkeys = Object.keys(missionsBlock);
                if (mkeys.length === 0) continue;
                const missionsOut = {};
                for (let j = 0; j < mkeys.length; j++) {
                    missionsOut[mkeys[j]] = { status: 'completed' };
                }
                missionData[setKey] = {
                    status: 'completed',
                    missions: missionsOut,
                };
            }
            return missionData;
        }

        function mergeMissionsetsByKeyList(data, setKeys, missionData) {
            if (!missionData || typeof missionData !== 'object' || !Array.isArray(setKeys)) {
                if (DEBUG) console.warn('[Preset] mergeMissionsetsByKeyList: invalid args');
                return;
            }
            if (!data || typeof data === 'string') {
                if (DEBUG) console.warn('[Preset] mergeMissionsetsByKeyList: invalid data');
                return;
            }
            if (!data.missions) data.missions = {};
            if (!data.missions.local_sets) data.missions.local_sets = {};
            const target = data.missions.local_sets;
            let n = 0;
            for (let i = 0; i < setKeys.length; i++) {
                const key = setKeys[i];
                if (!key || !missionData[key]) continue;
                target[key] = JSON.parse(JSON.stringify(missionData[key]));
                n++;
            }
            if (DEBUG) console.debug('[Preset] mergeMissionsetsByKeyList: merged', n, 'set(s)');
        }

        function resetLocalSetsMatching(predicate, setYamlOpts) {
            const data = getYamlDataFromTextarea();
            if (!data || typeof data === 'string') {
                showSaveStatus('save-preset-status', '⚠️ YAML required.', false);
                return 0;
            }
            if (!data.missions) data.missions = {};
            const ls = data.missions.local_sets;
            if (!ls || typeof ls !== 'object') {
                showSaveStatus('save-preset-status', '⚠️ No mission sets to reset.', false);
                return 0;
            }
            const keys = Object.keys(ls);
            let removed = 0;
            for (let i = 0; i < keys.length; i++) {
                const k = keys[i];
                try {
                    if (predicate(k)) {
                        delete ls[k];
                        removed++;
                    }
                } catch (_) {
                    /* ignore */
                }
            }
            if (removed > 0 && typeof setYamlDataToTextarea === 'function') {
                setYamlDataToTextarea(
                    data,
                    setYamlOpts || {
                        showChanges: true,
                        searchText: 'missions',
                        message: 'Updating missions…',
                        successMessage: '✅ Mission sets removed.',
                    }
                );
            }
            return removed;
        }

        function templateMissionsetKeys(missionData) {
            if (!missionData || typeof missionData !== 'object') return [];
            return Object.keys(missionData).filter((k) => k.startsWith('missionset_'));
        }

        function collectMissionsetKeysForZone(zoneId, allSetKeys) {
            const z = String(zoneId || '').toLowerCase();
            const keys = Array.isArray(allSetKeys) ? allSetKeys : [];
            return keys.filter((k) => {
                const isMainSide = k.startsWith('missionset_main_') || k.startsWith('missionset_side_');
                if (!isMainSide) return false;
                const rest = k.replace(/^missionset_main_/, '').replace(/^missionset_side_/, '');
                if (z === 'grasslands') {
                    return (
                        rest.indexOf('grasslands') !== -1 ||
                        rest.indexOf('beach') !== -1 ||
                        rest.indexOf('cowbell') !== -1
                    );
                }
                if (z === 'mountains') return rest.indexOf('mountains') !== -1;
                if (z === 'shatteredlands') return rest.indexOf('shatteredlands') !== -1;
                if (z === 'city') {
                    return (
                        (rest.indexOf('city') !== -1 || rest.indexOf('prison') !== -1) &&
                        rest.indexOf('elpis') === -1
                    );
                }
                if (z === 'elpis') return rest.indexOf('elpis') !== -1;
                return false;
            });
        }

        let __missionEditorManifestPromise = null;

        /**
         * Deep-merge Nexus mission sidecar (window.NEXUS_MISSION_MANIFEST) into legacy missions.yaml manifest.
         * Nexus wins for mission titles and optional metadata; adds missionset dependencies arrays.
         */
        function mergeNexusMissionManifestIntoLegacy(legacy, nexus) {
            const out =
                legacy && typeof legacy === "object"
                    ? JSON.parse(JSON.stringify(legacy))
                    : {};
            if (!nexus || typeof nexus !== "object") return out;
            const setKeys = Object.keys(nexus);
            for (let i = 0; i < setKeys.length; i++) {
                const setKey = setKeys[i];
                const nSet = nexus[setKey];
                if (!nSet || typeof nSet !== "object") continue;
                if (!out[setKey] || typeof out[setKey] !== "object") out[setKey] = {};
                if (!out[setKey].missions || typeof out[setKey].missions !== "object") {
                    out[setKey].missions = {};
                }
                if (Array.isArray(nSet.dependencies) && nSet.dependencies.length > 0) {
                    out[setKey].dependencies = nSet.dependencies.slice();
                }
                const nm = nSet.missions && typeof nSet.missions === "object" ? nSet.missions : {};
                const mkeys = Object.keys(nm);
                for (let j = 0; j < mkeys.length; j++) {
                    const mk = mkeys[j];
                    const nMeta = nm[mk];
                    if (!out[setKey].missions[mk] || typeof out[setKey].missions[mk] !== "object") {
                        out[setKey].missions[mk] = {};
                    }
                    const target = out[setKey].missions[mk];
                    if (nMeta && typeof nMeta === "object") {
                        if (typeof nMeta.title === "string" && nMeta.title.trim()) {
                            target.title = nMeta.title.trim();
                        }
                        if (typeof nMeta.missiontype === "string" && nMeta.missiontype.trim()) {
                            target.missiontype = nMeta.missiontype.trim();
                        }
                        if (typeof nMeta.worldregion === "string" && nMeta.worldregion.trim()) {
                            target.worldregion = nMeta.worldregion.trim();
                        }
                        if (typeof nMeta.missiondifficulty === "string" && nMeta.missiondifficulty.trim()) {
                            target.missiondifficulty = nMeta.missiondifficulty.trim();
                        }
                        if (typeof nMeta.platformactivityid === "string" && nMeta.platformactivityid.trim()) {
                            target.platformactivityid = nMeta.platformactivityid.trim();
                        }
                        if (nMeta.rememberedFinals && typeof nMeta.rememberedFinals === "object") {
                            const rf = nMeta.rememberedFinals;
                            const rkeys = Object.keys(rf);
                            if (rkeys.length > 0) {
                                target.rememberedFinals = {};
                                for (let ri = 0; ri < rkeys.length; ri++) {
                                    const rk = rkeys[ri];
                                    target.rememberedFinals[rk] = rf[rk];
                                }
                            }
                        }
                    }
                }
            }
            return out;
        }

        function missionManifestIsEmpty(obj) {
            return !obj || typeof obj !== "object" || Object.keys(obj).length === 0;
        }

        function manifestTitleFromNode(node, fallback) {
            if (!node || typeof node !== "object") return fallback || null;
            if (typeof node.title === "string" && node.title.trim()) {
                return node.title.trim();
            }
            if (typeof node.display_name === "string" && node.display_name.trim()) {
                return node.display_name.trim();
            }
            return fallback || null;
        }

        async function ensureMissionEditorManifest() {
            if (window.__missionEditorManifest && window.__missionEditorManifest.loaded) {
                return window.__missionEditorManifest.raw;
            }
            if (!__missionEditorManifestPromise) {
                __missionEditorManifestPromise = loadMissionData()
                    .then((legacy) => {
                        const nexus =
                            typeof window !== "undefined" &&
                            window.NEXUS_MISSION_MANIFEST &&
                            typeof window.NEXUS_MISSION_MANIFEST === "object"
                                ? window.NEXUS_MISSION_MANIFEST
                                : null;
                        const merged = mergeNexusMissionManifestIntoLegacy(
                            legacy && typeof legacy === "object" ? legacy : null,
                            nexus
                        );
                        const raw = missionManifestIsEmpty(merged)
                            ? legacy && typeof legacy === "object"
                                ? legacy
                                : null
                            : merged;
                        window.__missionEditorManifest = {
                            loaded: true,
                            raw,
                        };
                        return window.__missionEditorManifest.raw;
                    })
                    .catch(() => {
                        const nexus =
                            typeof window !== "undefined" &&
                            window.NEXUS_MISSION_MANIFEST &&
                            typeof window.NEXUS_MISSION_MANIFEST === "object"
                                ? window.NEXUS_MISSION_MANIFEST
                                : null;
                        const merged = mergeNexusMissionManifestIntoLegacy(null, nexus);
                        const raw = missionManifestIsEmpty(merged) ? null : merged;
                        window.__missionEditorManifest = { loaded: true, raw };
                        return raw;
                    });
            }
            return __missionEditorManifestPromise;
        }

        function getManifestMissionsetNode(manifest, setKey) {
            if (!manifest || !setKey) return null;
            return manifest[setKey] || null;
        }

        function getManifestMissionNode(manifest, setKey, missionKey) {
            const setNode = getManifestMissionsetNode(manifest, setKey);
            const block = setNode && setNode.missions;
            if (!block || typeof block !== "object") return null;
            return block[missionKey] || null;
        }

        function manifestFirstMissionTitleInSet(manifest, setKey) {
            const node = getManifestMissionsetNode(manifest, setKey);
            const block = node && node.missions;
            if (!block || typeof block !== "object") return null;
            const mkeys = Object.keys(block).sort();
            for (let i = 0; i < mkeys.length; i++) {
                const t = manifestTitleFromNode(block[mkeys[i]], null);
                if (t) return t;
            }
            return null;
        }

        async function completeAllStoryMissions() {
            let data = getYamlDataFromTextarea();
            if (!data || typeof data === 'string') {
                if (DEBUG) console.warn('[Preset] completeAllStoryMissions: This preset requires YAML parsing.');
                showSaveStatus('save-preset-status', '⚠️ This preset requires YAML parsing. Please ensure js-yaml is loaded.', false);
                return;
            }

            if (DEBUG) console.debug('[Preset] completeAllStoryMissions: Completing all story missions');

            // Try to load and merge mission data (network-first + Nexus stubs for missing DLC sets)
            const rawStory = await getMissionTemplateDataForMerge();
            let missionData =
                rawStory && typeof rawStory === 'object' ? JSON.parse(JSON.stringify(rawStory)) : null;
            if (missionData) augmentMissionTemplatesWithNexusStubs(missionData);
            if (missionData) {
                // Get fresh data for merging
                data = getYamlDataFromTextarea();
                
                // Merge all main story mission sets (except epilogue which we'll handle separately)
                mergeMissionsetsWithPrefix(data, 'missionset_main_', missionData);
                applyNexusRememberedFinalsToLocalSets(data);

                // Stage epilogue mission to unlock specializations (overwrites the merged one)
                stageEpilogueMission(data);
                
                // Set story values
                setStoryValues(data);
                
                // Write everything back at once
                setYamlDataToTextarea(data, {
                    showChanges: true,
                    searchText: 'missionset_main_cityepilogue',
                    fallbackSearchText: 'mission_main_all',
                    message: 'Completing all story missions...',
                    successMessage: '✅ All story missions completed!'
                });
            } else {
                // Fallback: only update existing mission sets if we can't load the data
                showSaveStatus('save-preset-status', '⚠️ Could not load missions.yaml. Only updating existing mission sets.', false);
                
                data = getYamlDataFromTextarea();
                if (!data.missions) data.missions = {};
                if (!data.missions.local_sets) data.missions.local_sets = {};

                for (const missionSetKey in data.missions.local_sets) {
                    if (missionSetKey.startsWith('missionset_main_') && missionSetKey !== 'missionset_main_cityepilogue') {
                        const missionSet = data.missions.local_sets[missionSetKey];
                        missionSet.status = 'completed';
                        
                        if (missionSet.missions) {
                            for (const missionKey in missionSet.missions) {
                                if (missionSet.missions.hasOwnProperty(missionKey) && typeof missionSet.missions[missionKey] === 'object') {
                                    missionSet.missions[missionKey].status = 'completed';
                                }
                            }
                        }
                    }
                }
                
                stageEpilogueMission(data);
                setStoryValues(data);
                
                setYamlDataToTextarea(data, {
                    showChanges: true,
                    searchText: 'missionset_main_cityepilogue',
                    fallbackSearchText: 'mission_main_all',
                    message: 'Completing all story missions...',
                    successMessage: '✅ All story missions completed!'
                });
            }

            if (DEBUG) console.debug('[Preset] completeAllStoryMissions: Story missions completed');
        }

        /**
         * Stages the epilogue mission to unlock specializations
         * @param {Object} data - The save data object to modify
         */
        function stageEpilogueMission(data) {
            if (!data || typeof data === 'string') return;

            if (!data.missions) data.missions = {};
            if (!data.missions.local_sets) data.missions.local_sets = {};

            // Stage epilogue mission to unlock specializations (should be Active, not completed)
            data.missions.local_sets['missionset_main_cityepilogue'] = {
                missions: {
                    mission_main_cityepilogue: {
                        status: 'Active',
                        cursorposition: 8,
                        final: {
                            inv_openportal_endstate: 'completed',
                            phasedimensionentered_1st: true,
                            defeat_arjay_endstate: 'completed',
                            take_object_endstate: 'completed',
                        },
                        objectives: {
                            entervault: { status: 'Completed_PostFinished' },
                            defeat_arjay: { status: 'Completed_PostFinished' },
                            entervault_todefeatarjay: { status: 'Deactivated_PostFinished' },
                            explore_vault: { status: 'Completed_PostFinished' },
                            lootchests: { status: 'Completed_PostFinished', updatecount: 4 },
                            returntomoxxisbar: { status: 'Completed_Finishing' },
                            speaktolilith: { status: 'Completed_PostFinished' },
                            take_object: { status: 'Completed_PostFinished' },
                            inv_readyforspeaktolilith: { status: 'Completed_PostFinished' },
                            _lootchests_sub3: { status: 'Completed_PostFinished' },
                            _lootchests_sub1: { status: 'Completed_PostFinished' },
                            _lootchests_sub2: { status: 'Completed_PostFinished' },
                            _lootchests_sub0: { status: 'Completed_PostFinished' },
                            inv_playerarrivedatfinalplatform: { status: 'Completed_PostFinished' },
                            inv_openportal: { status: 'Completed_PostFinished' },
                            inv_interactwithrift: { status: 'Completed_PostFinished' },
                        },
                    },
                },
            };
        }

        /**
         * Sets story completion values
         * @param {Object} data - The save data object to modify
         */
        function setStoryValues(data) {
            if (!data || typeof data === 'string') return;

            if (!data.globals) data.globals = {};
            data.globals.lockdownlifted = true;
            if (!data.stats) data.stats = {};
            if (!data.stats.challenge) data.stats.challenge = {};
            data.stats.challenge.mission_main_all = 18;

            if (!data.unlockables) data.unlockables = {};
            if (!data.unlockables.character_progress) data.unlockables.character_progress = {};
            let entries = data.unlockables.character_progress.entries || [];
            if (!entries.includes('character_progress.seen_credits')) {
                entries.push('character_progress.seen_credits');
            }
            data.unlockables.character_progress.entries = entries;
        }

        /**
         * Completes all missions
         */
        async function completeAllMissions() {
            let data = getYamlDataFromTextarea();
            if (!data || typeof data === 'string') {
                if (DEBUG) console.warn('[Preset] completeAllMissions: This preset requires YAML parsing.');
                showSaveStatus('save-preset-status', '⚠️ This preset requires YAML parsing. Please ensure js-yaml is loaded.', false);
                return;
            }

            if (DEBUG) console.debug('[Preset] completeAllMissions: Completing all missions');

            // Load and merge ALL mission sets (network missions.yaml + Nexus stubs for new DLC)
            const rawAll = await getMissionTemplateDataForMerge();
            let missionData =
                rawAll && typeof rawAll === 'object' ? JSON.parse(JSON.stringify(rawAll)) : null;
            if (missionData) augmentMissionTemplatesWithNexusStubs(missionData);
            if (missionData) {
                // Get fresh data for merging
                data = getYamlDataFromTextarea();
                
                // Merge ALL mission sets (missionset_main_, missionset_side_, missionset_micro_, missionset_zoneactivity_, missionset_vault_, etc.)
                const mergedAllKeys = mergeMissionsetsWithPrefix(data, 'missionset_', missionData);
                applyNexusRememberedFinalsToLocalSets(data);

                const lsAfterMerge = data.missions && data.missions.local_sets;
                let hasCowbellLocalSet = false;
                if (lsAfterMerge && typeof lsAfterMerge === 'object') {
                    const lsK = Object.keys(lsAfterMerge);
                    for (let ci = 0; ci < lsK.length; ci++) {
                        if (missionSetKeyIsCowbellDlcContent(lsK[ci])) {
                            hasCowbellLocalSet = true;
                            break;
                        }
                    }
                }
                if (mergedSetKeysTouchCowbellOpenworld(mergedAllKeys) || hasCowbellLocalSet) {
                    applyCowbellSpeakeasyPortalOpenworldStats(data);
                }

                // Stage epilogue mission to unlock specializations (overwrites the merged one)
                stageEpilogueMission(data);
                
                // Set story values
                if (typeof setStoryValues === 'function') setStoryValues(data);
                
                // Write everything back
                setYamlDataToTextarea(data, {
                    showChanges: true,
                    searchText: 'missionset_',
                    fallbackSearchText: 'missions',
                    message: 'Completing all missions...',
                    successMessage: '✅ All missions completed!'
                });
                
            } else {
                // Fallback: use existing functions if we can't load the data
                showSaveStatus('save-preset-status', '⚠️ Could not load missions.yaml. Using fallback method.', false);
                
                // Complete story missions only (no safehouse/SDU side effects)
                await completeAllStoryMissions();
            }

            if (DEBUG) console.debug('[Preset] completeAllMissions: All missions completed');
        }

        /**
         * Resets all missions (removes all mission data)
         * This is the opposite of completeAllMissions - it clears all mission data from the save
         */
        function resetAllMissions() {
            let data = getYamlDataFromTextarea();
            if (!data || typeof data === 'string') {
                if (DEBUG) console.warn('[Preset] resetAllMissions: This preset requires YAML parsing.');
                showSaveStatus('save-preset-status', '⚠️ This preset requires YAML parsing. Please ensure js-yaml is loaded.', false);
                return;
            }

            if (DEBUG) console.debug('[Preset] resetAllMissions: Resetting all missions');

            // Initialize missions structure if it doesn't exist
            if (!data.missions) data.missions = {};
            
            // Clear all mission sets (reset to empty object)
            data.missions.local_sets = {};

            // Write the changes back
            setYamlDataToTextarea(data, {
                showChanges: true,
                searchText: 'missions',
                message: 'Resetting all missions...',
                successMessage: '✅ All missions reset!'
            });

            if (DEBUG) console.debug('[Preset] resetAllMissions: All missions reset');
        }

        /**
         * Resets all missions except the prologue (leaves prologue mission completed)
         * This is similar to resetAllMissions but keeps the prison prologue mission completed
         */
        function resetAllMissionsSkipPrologue() {
            let data = getYamlDataFromTextarea();
            if (!data || typeof data === 'string') {
                if (DEBUG) console.warn('[Preset] resetAllMissionsSkipPrologue: This preset requires YAML parsing.');
                showSaveStatus('save-preset-status', '⚠️ This preset requires YAML parsing. Please ensure js-yaml is loaded.', false);
                return;
            }

            if (DEBUG) console.debug('[Preset] resetAllMissionsSkipPrologue: Resetting all missions except prologue');

            // Initialize missions structure if it doesn't exist
            if (!data.missions) data.missions = {};
            
            // Clear all mission sets (reset to empty object)
            data.missions.local_sets = {};

            // Set the prison prologue mission to completed state
            data.missions.local_sets['missionset_main_prisonprologue'] = {
                status: 'completed',
                missions: {
                    mission_main_prisonprologue: {
                        status: 'completed',
                        final: {
                            obj_firstswim_endstate: 'completed'
                        }
                    }
                }
            };

            // Write the changes back
            setYamlDataToTextarea(data, {
                showChanges: true,
                searchText: 'missions',
                message: 'Resetting all missions except prologue...',
                successMessage: '✅ All missions reset (prologue kept)!'
            });

            if (DEBUG) console.debug('[Preset] resetAllMissionsSkipPrologue: All missions reset except prologue');
        }

        async function completeDlcMissionsBulk() {
            let data = getYamlDataFromTextarea();
            if (!data || typeof data === 'string') {
                showSaveStatus('save-preset-status', '⚠️ This preset requires YAML parsing.', false);
                return;
            }
            const raw = await getMissionTemplateDataForMerge();
            let missionData = raw && typeof raw === 'object' ? JSON.parse(JSON.stringify(raw)) : null;
            if (!missionData) {
                showSaveStatus('save-preset-status', '⚠️ Could not load mission templates.', false);
                return;
            }
            augmentMissionTemplatesWithNexusStubs(missionData);
            data = getYamlDataFromTextarea();
            const mergedDlcKeys = mergeMissionsetsWithPrefix(data, 'missionset_dlc_', missionData);
            const cowbellKeysFromTemplates = Object.keys(missionData).filter(missionSetKeyIsCowbellDlcContent);
            let mergedCowbellSets = false;
            if (cowbellKeysFromTemplates.length) {
                mergeMissionsetsByKeyList(data, cowbellKeysFromTemplates, missionData);
                mergedCowbellSets = true;
            }
            if (mergedSetKeysTouchCowbellOpenworld(mergedDlcKeys) || mergedCowbellSets) {
                applyCowbellSpeakeasyPortalOpenworldStats(data);
            }
            applyNexusRememberedFinalsToLocalSets(data);
            setYamlDataToTextarea(data, {
                showChanges: true,
                searchText: 'missionset_dlc_',
                fallbackSearchText: 'missions',
                message: 'Completing DLC missions…',
                successMessage: '✅ DLC missions completed (template merge).',
            });
        }

