                        var pid = simplePartIds[i];
                        var fullId = typeId + ':' + pid;
                        var partInfo = partsMap.get(fullId) || (partsByTypeId.get(typeId) && partsByTypeId.get(typeId).find(function(p) { return String(p.id) === String(pid) || String(p.fullId) === fullId; }));
                        var rawPart = typeof getPartFromGameData === 'function' ? getPartFromGameData(fullId) : null;
                        var partTypeStr = (partInfo && (partInfo.partType || partInfo.path || partInfo.spawnCode || '')) || (rawPart && (rawPart.type || rawPart.part_type || '')) || '';
                        var isBody = /Legendary Body|body|leg_body/i.test(partTypeStr) || (rawPart && rawPart.type === 'Legendary Body');
                        if (!isBody) continue;
                        var str = (partInfo && (partInfo.spawnCode || partInfo.string || partInfo.modelName)) || (rawPart && (rawPart.spawn_code || rawPart.spawnCode || rawPart.string)) || fullId;
                        var displayName = (partInfo && partInfo.name) || (rawPart && rawPart.name) || '';
