                    var displayName = partInfo.name || partInfo.legendaryName || (rawPart && rawPart.name) || '';
                    var name = displayName ? code + ' (' + displayName + ')' : code;
                    var hasPartBarrelCode = /part_barrel|\.part_barrel/i.test(String(code));
