        window.missionEditorJumpFromButton = function missionEditorJumpFromButton(btn) {
            if (!btn || !btn.dataset || !btn.dataset.jump) return;
            let o;
            try {
                o = JSON.parse(decodeURIComponent(btn.dataset.jump));
            } catch (_) {
                return;
            }
            const openBranch = function (contentPrefix, togglePrefix, id) {
                if (!id) return;
                const content = document.getElementById(contentPrefix + id);
                const toggle = document.getElementById(togglePrefix + id);
                if (content) content.style.display = 'flex';
                if (toggle) toggle.textContent = '▼';
            };
            openBranch('group-content-', 'group-toggle-', o.g);
            openBranch('subgroup-content-', 'subgroup-toggle-', o.s);
            openBranch('missionset-content-', 'missionset-toggle-', o.m);
            if (o.r) {
                const row = document.getElementById(o.r);
                if (row) row.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
            }
        };

