        // Quick remove Rainbow Vomit parts - removes all parts containing "rainbowvomit" in spawn code
        async function quickRemoveRainbowVomit() {
            // Check if any process is running
            if (window.saveEditorState.isProcessing) {
                showSaveStatus('quick-remove-status', '❌ Cannot remove parts while another process is running. Please wait.', false);
                return;
            }
            
            // Set processing state
            setSaveProcessingState(true, 'Removing Rainbow Vomit parts');
            
            try {
                // Read all backpack items from YAML directly
                const data = getYamlDataFromTextarea();
                if (!data || typeof data === 'string') {
                    showSaveStatus('quick-remove-status', '❌ This feature requires YAML parsing. Please ensure js-yaml is loaded.', false);
                    setSaveProcessingState(false);
                    return;
                }
                
                const backpackSlots = data.state?.inventory?.items?.backpack;
                if (!backpackSlots) {
                    showSaveStatus('quick-remove-status', '❌ No backpack items found in YAML.', false);
                    setSaveProcessingState(false);
                    return;
                }
                
                const slotKeys = Object.keys(backpackSlots);
                const totalItems = slotKeys.length;
                
                if (totalItems === 0) {
                    showSaveStatus('quick-remove-status', '⚠️ No items found in backpack.', false);
                    setSaveProcessingState(false);
                    return;
                }
                
                showSaveStatus('quick-remove-status', `⏳ Processing ${totalItems} items... Deserializing...`, true);
                
                // Step 1: Collect all serials and deserialize in bulk (ONE API CALL)
                const serials = [];
                slotKeys.forEach((slotKey) => {
                    const slot = backpackSlots[slotKey];
                    if (slot && slot.serial) {
                        serials.push(slot.serial);
                    }
                });
                
                if (serials.length === 0) {
                    showSaveStatus('quick-remove-status', '⚠️ No serials found in backpack items.', false);
                    setSaveProcessingState(false);
                    return;
                }
                
                // Bulk deserialize all serials (ONE API CALL)
                const deserializeResults = await deserializeSerialsBulk(serials);
                const deserializedMap = deserializeResults.results || {};
                
                showSaveStatus('quick-remove-status', `⏳ Searching for Rainbow Vomit parts...`, true);
                
                // Step 2: Load game data to identify Rainbow Vomit parts
                // We need to check which parts have "rainbowvomit" in their spawn code
                let rainbowVomitPartIds = new Set();
                
                if (window.gameData && window.gameData.parts) {
                    window.gameData.parts.forEach(part => {
                        const spawnCode = (part.spawn_code || part.spawnCode || '').toLowerCase();
                        if (spawnCode.includes('rainbowvomit')) {
                            // Parse part ID (format: "typeId:partId")
                            const idMatch = (part.id || '').match(/^(\d+):(\d+)$/);
                            if (idMatch) {
                                const typeId = idMatch[1];
                                const partId = idMatch[2];
                                rainbowVomitPartIds.add(`${typeId}:${partId}`);
                            }
                        }
                    });
                }
                
                // Also check known Rainbow Vomit parts from the data provided
                // TypeId 9 parts with IDs: 1, 16, 71, 72, 73, 74, 75, 76, 77, 84, 86
                const knownRainbowVomitParts = ['9:1', '9:16', '9:71', '9:72', '9:73', '9:74', '9:75', '9:76', '9:77', '9:84', '9:86'];
                knownRainbowVomitParts.forEach(id => rainbowVomitPartIds.add(id));
                
                if (rainbowVomitPartIds.size === 0) {
                    showSaveStatus('quick-remove-status', '⚠️ No Rainbow Vomit parts found in game data.', false);
                    setSaveProcessingState(false);
                    return;
                }
                
                showSaveStatus('quick-remove-status', `⏳ Removing ${rainbowVomitPartIds.size} Rainbow Vomit part types from ${serials.length} items...`, true);
                
                // Step 3: Process all decoded codes and remove Rainbow Vomit parts
                const modifiedCodes = [];
                const itemsToUpdate = [];
                let removedCount = 0;
                
                slotKeys.forEach((slotKey) => {
                    const slot = backpackSlots[slotKey];
                    if (!slot || !slot.serial) return;
                    
                    const originalSerial = slot.serial;
                    const decodedCode = deserializedMap[originalSerial]?.deserialized || deserializedMap['@' + originalSerial]?.deserialized;
                    
                    if (!decodedCode || !decodedCode.includes('||')) {
                        return;
                    }
                    
                    // Extract parts section
                    const partsMatch = decodedCode.match(/\|\|\s*(.+?)(?:\s*\|)?$/);
                    if (!partsMatch) return;
                    
                    let partsSection = partsMatch[1];
                    let partsChanged = false;
                    
                    // Remove all Rainbow Vomit parts
                    rainbowVomitPartIds.forEach(partIdStr => {
                        const [typeId, partId] = partIdStr.split(':');
                        
                        // Remove simple parts (e.g., {9:1})
                        const simplePartPattern = new RegExp(`\\{${typeId}:${partId}\\}`, 'g');
                        if (simplePartPattern.test(partsSection)) {
                            partsSection = partsSection.replace(simplePartPattern, '');
                            partsChanged = true;
                        }
                        
                        // Remove from arrays (e.g., remove 1 from {9:[1 11]})
                        const arrayPattern = new RegExp(`\\{${typeId}:\\[([^\\]]+)\\]\\}`, 'g');
                        partsSection = partsSection.replace(arrayPattern, (match, arrayContents) => {
                            const arrayParts = arrayContents.trim().split(/\s+/).map(n => n.trim()).filter(n => n.length > 0);
                            const filteredParts = arrayParts.filter(p => p !== partId);
                            
                            if (filteredParts.length === 0) {
                                partsChanged = true;
                                return ''; // Remove entire array part
                            } else if (filteredParts.length === arrayParts.length) {
                                return match; // Part not found, no change
                            } else {
                                partsChanged = true;
                                if (filteredParts.length === 1) {
                                    return `{${typeId}:${filteredParts[0]}}`; // Convert to simple part
                                } else {
                                    return `{${typeId}:[${filteredParts.join(' ')}]}`; // Keep as array
                                }
                            }
                        });
                    });
                    
                    if (partsChanged) {
                        // Clean up extra spaces
                        const cleanedParts = partsSection.replace(/\s+/g, ' ').trim();
                        
                        // Rebuild the code
                        const codeBeforeParts = decodedCode.substring(0, partsMatch.index + 2);
                        const codeAfterParts = decodedCode.substring(partsMatch.index + partsMatch[0].length);
                        const newCode = codeBeforeParts + (cleanedParts ? ' ' + cleanedParts : '') + (codeAfterParts.trim() ? ' ' + codeAfterParts.trim() : '');
                        
                        modifiedCodes.push(newCode);
                        itemsToUpdate.push({ slotKey, slot, newCode });
                        removedCount++;
                    }
                });
                
                if (removedCount === 0) {
                    showSaveStatus('quick-remove-status', '⚠️ No Rainbow Vomit parts found in any items.', false);
                    setSaveProcessingState(false);
                    return;
                }
                
                showSaveStatus('quick-remove-status', `⏳ Reserializing ${removedCount} modified items...`, true);
                
                // Step 4: Reserialize all modified codes in bulk (ONE API CALL)
                if (modifiedCodes.length > 0) {
                    const normalizedCodes = modifiedCodes.map(code => ensureTrailingPipe(code));
                    
                    let serializedResults = [];
                    let apiError = null;
                    
                    try {
                        const controller = new AbortController();
                        const timeoutId = setTimeout(() => controller.abort(), 120000);
                        
                        const apiBaseUrl = (typeof getLocalApiUrl === 'function') ? getLocalApiUrl() : (typeof API_BASE_URL !== 'undefined' ? API_BASE_URL : 'https://save-editor.be/nicnl/api.php');
                        
                        const response = await fetch(apiBaseUrl, {
                            method: "POST",
                            headers: { "Content-Type": "application/json" },
                            body: JSON.stringify({ deserialized_strings: normalizedCodes }),
                            signal: controller.signal,
                        });
                        clearTimeout(timeoutId);
                        
                        if (response.ok) {
                            const data = await response.json();
                            if (Array.isArray(data) && data.length === normalizedCodes.length) {
                                serializedResults = data;
                            } else {
                                apiError = 'API returned invalid format or wrong length';
                            }
                        } else {
                            const errorText = await response.text();
                            apiError = `API responded with ${response.status}: ${errorText}`;
                        }
                    } catch (error) {
                        console.warn("Primary API bulk serialize failed:", error.message);
                        apiError = error.message;
                        
                        try {
                            const controller = new AbortController();
                            const timeoutId = setTimeout(() => controller.abort(), 120000);
                            
                            const apiFallbackUrl = (typeof API_FALLBACK_URL !== 'undefined') ? API_FALLBACK_URL : 'https://save-editor.be/nicnl/api.php';
                            
                            const response = await fetch(apiFallbackUrl, {
                                method: "POST",
                                headers: { "Content-Type": "application/json" },
                                body: JSON.stringify({ deserialized_strings: normalizedCodes }),
                                signal: controller.signal,
                            });
                            clearTimeout(timeoutId);
                            
                            if (response.ok) {
                                const data = await response.json();
                                if (Array.isArray(data) && data.length === normalizedCodes.length) {
                                    serializedResults = data;
                                    apiError = null;
                                } else {
                                    apiError = 'Fallback API returned invalid format or wrong length';
                                }
                            } else {
                                apiError = `Fallback API responded with ${response.status}`;
                            }
                        } catch (fallbackError) {
                            apiError = `Both APIs failed. Last error: ${fallbackError.message}`;
                        }
                    }
                    
                    if (apiError) {
                        throw new Error(`Failed to reserialize items: ${apiError}`);
                    }
                    
                    // Step 5: Update YAML with new serials
                    if (serializedResults.length === itemsToUpdate.length) {
                        itemsToUpdate.forEach((item, index) => {
                            if (serializedResults[index] && serializedResults[index].trim()) {
                                item.slot.serial = serializedResults[index].trim();
                            }
                        });
                        
                        setYamlDataToTextarea(data, {
                            showChanges: true,
                            searchText: 'backpack',
                            fallbackSearchText: 'inventory',
                            message: `Updating ${removedCount} items...`,
                            successMessage: `✅ Removed Rainbow Vomit parts from ${removedCount} item${removedCount === 1 ? '' : 's'} (out of ${totalItems} total).`
                        });
                        
                        if (typeof decodeYamlInventory === 'function') {
                            setTimeout(async () => {
                                try {
                                    const yamlValue = getYamlTextareaValue();
                                    if (yamlValue) {
                                        await decodeYamlInventory(yamlValue, {
                                            baseMessage: "✅ Decoded items updated.",
                                            statusElementId: 'quick-remove-status',
                                            showStatus: false,
                                            itemDecode: "none",
                                        });
                                    }
                                } catch (err) {
                                    console.warn('Failed to re-decode items:', err);
                                }
                            }, 500);
                        }
                        
                        showSaveStatus('quick-remove-status', `✅ Removed Rainbow Vomit parts from ${removedCount} item${removedCount === 1 ? '' : 's'} (out of ${totalItems} total).`, true);
                    } else {
                        throw new Error(`Serialization result count mismatch: expected ${itemsToUpdate.length}, got ${serializedResults.length}`);
                    }
                }
            } catch (err) {
                console.error('Failed to remove Rainbow Vomit parts:', err);
                showSaveStatus('quick-remove-status', `❌ Error removing Rainbow Vomit parts: ${err.message}`, false);
            } finally {
                setSaveProcessingState(false);
            }
        }

        function loadProfileYamlDataForMassEdit() {
            if (!window.profileMonacoEditor) return null;
            let raw = window.profileMonacoEditor.getValue();
            if (!raw || !String(raw).trim()) return null;
            let cleanedYaml = raw.replace(/:\s*!tags/g, ':').replace(/:\s*!<[^>]+>/g, ':');
            try {
                const d = jsyaml.load(cleanedYaml);
                return d && typeof d === 'object' ? d : null;
            } catch (parseError) {
                try {
                    const d = jsyaml.load(cleanedYaml.replace(/!<[^>]+>/g, ''));
                    return d && typeof d === 'object' ? d : null;
                } catch (_) {
                    return null;
                }
            }
        }

        function ensureProfileBankObject(data) {
            if (!data.domains) data.domains = {};
            if (!data.domains.local) data.domains.local = {};
            if (!data.domains.local.shared) data.domains.local.shared = {};
            if (!data.domains.local.shared.inventory) data.domains.local.shared.inventory = {};
            if (!data.domains.local.shared.inventory.items) data.domains.local.shared.inventory.items = {};
            if (!data.domains.local.shared.inventory.items.bank) data.domains.local.shared.inventory.items.bank = {};
            return data.domains.local.shared.inventory.items.bank;
        }

        function ensureProfileInventoryItemsObject(data) {
            if (!data.domains) data.domains = {};
            if (!data.domains.local) data.domains.local = {};
            if (!data.domains.local.shared) data.domains.local.shared = {};
            if (!data.domains.local.shared.inventory) data.domains.local.shared.inventory = {};
            if (!data.domains.local.shared.inventory.items) data.domains.local.shared.inventory.items = {};
            return data.domains.local.shared.inventory.items;
        }

        function blackMarketYamlSeqToArray(val) {
            if (val == null) return [];
            if (Array.isArray(val)) return val;
            if (typeof val === 'object') {
                const keys = Object.keys(val);
                const allNumeric = keys.length > 0 && keys.every(k => /^\d+$/.test(k));
                if (allNumeric) {
                    keys.sort((a, b) => parseInt(a, 10) - parseInt(b, 10));
                }
                return keys.map(k => val[k]);
            }
            return [];
        }

        function profileDataGetBlackMarketItemsArray(data) {
            const shared = data && data.domains && data.domains.local && data.domains.local.shared;
            if (shared && shared.blackmarket_items != null) {
                return blackMarketYamlSeqToArray(shared.blackmarket_items);
            }
            const items = shared && shared.inventory && shared.inventory.items;
            if (items && items.blackmarket_items != null) {
                return blackMarketYamlSeqToArray(items.blackmarket_items);
            }
            return [];
        }

        function profileDataParseBlackMarketRow(row) {
            if (!row || typeof row !== 'object') {
                return { itemcomp: '', itemtype: '', gamestage: 60 };
            }
            const comp =
                row.blackmarket_itemcomp != null ? String(row.blackmarket_itemcomp).trim() : '';
            let typ = row.blackmarket_itemtype != null ? String(row.blackmarket_itemtype).trim() : '';
            const gsRaw = row.blackmarket_gamestage;
            const gs = gsRaw != null && gsRaw !== '' ? Number(gsRaw) : 60;
            if (!typ && comp.indexOf('.') >= 0) {
                typ = comp.split('.')[0];
            }
            return {
                itemcomp: comp,
                itemtype: typ,
                gamestage: Number.isFinite(gs) ? gs : 60
            };
        }

        function profileDataApplyBlackMarketItems(data, slotRows) {
            if (!data.domains) data.domains = {};
            if (!data.domains.local) data.domains.local = {};
            if (!data.domains.local.shared) data.domains.local.shared = {};
            const shared = data.domains.local.shared;
            const list = [];
            const two = Array.isArray(slotRows) ? slotRows.slice(0, 2) : [];
            for (let i = 0; i < two.length; i++) {
                const r = two[i] || {};
                const comp = r.itemcomp != null ? String(r.itemcomp).trim() : '';
                if (!comp) continue;
                const dot = comp.indexOf('.');
                const itemtype =
                    dot >= 0
                        ? comp.slice(0, dot)
                        : r.itemtype != null
                          ? String(r.itemtype).trim()
                          : '';
                if (!itemtype) continue;
                const gs = r.gamestage != null ? Number(r.gamestage) : 60;
                list.push({
                    blackmarket_itemtype: itemtype,
                    blackmarket_itemcomp: comp,
                    blackmarket_gamestage: Number.isFinite(gs) ? gs : 60
                });
            }
            shared.blackmarket_items = list;
            const legacyItems = shared.inventory && shared.inventory.items;
            if (legacyItems && legacyItems.blackmarket_items != null) {
                delete legacyItems.blackmarket_items;
            }
            return { ok: true, count: list.length };
        }

        function profileApplyBlackMarketSlotsFromUi(slotRows) {
            if (!window.profileMonacoEditor) {
                return { ok: false, error: 'Decrypt profile and open the YAML editor first.' };
            }
            const data = loadProfileYamlDataForMassEdit();
            if (!data) {
                return { ok: false, error: 'Could not parse profile YAML.' };
            }
            const two = Array.isArray(slotRows) ? slotRows.slice(0, 2) : [];
            if (two.length !== 2) {
                return { ok: false, error: 'The black market machine has exactly two slots.' };
            }
            for (let i = 0; i < two.length; i++) {
                if (!two[i] || !String(two[i].itemcomp || '').trim()) {
                    return { ok: false, error: 'Slot ' + (i + 1) + ' has no legendary selected.' };
                }
            }
            const r = profileDataApplyBlackMarketItems(data, two);
            saveProfileYamlFromMassEditData(data);
            return { ok: true, count: r.count };
        }

        window.ensureProfileInventoryItemsObject = ensureProfileInventoryItemsObject;
        window.profileDataGetBlackMarketItemsArray = profileDataGetBlackMarketItemsArray;
        window.profileDataParseBlackMarketRow = profileDataParseBlackMarketRow;
        window.profileDataApplyBlackMarketItems = profileDataApplyBlackMarketItems;
        window.profileApplyBlackMarketSlotsFromUi = profileApplyBlackMarketSlotsFromUi;
        window.loadProfileYamlDataForMassEdit = loadProfileYamlDataForMassEdit;

        function saveProfileYamlFromMassEditData(data) {
            if (!window.profileMonacoEditor) return;
            const newYaml = jsyaml.dump(data, { lineWidth: -1, noRefs: true });
            window.profileMonacoEditor.setValue(newYaml);
            if (typeof decodeProfileBankAndCosmetics === 'function') {
                decodeProfileBankAndCosmetics(newYaml);
            }
        }

        async function profileMassChangeLevel() {
            if (window.saveEditorState.isProcessing) {
                showSaveStatus('bank-items-status', '❌ Cannot change levels while another process is running. Please wait.', false);
                return;
            }
            const levelInput = document.getElementById('profile-mass-level-input');
            const newLevel = levelInput ? parseInt(levelInput.value, 10) : NaN;
            if (!newLevel || newLevel < 1 || newLevel > 60) {
                showSaveStatus('bank-items-status', '❌ Enter a valid level between 1 and 60.', false);
                return;
            }
            setSaveProcessingState(true, 'Profile bank: change levels');
            try {
                const data = loadProfileYamlDataForMassEdit();
                if (!data) {
                    showSaveStatus('bank-items-status', '❌ Could not parse profile YAML.', false);
                    return;
                }
                const bank = ensureProfileBankObject(data);
                let updatedCount = 0;
                for (const slot of Object.values(bank)) {
                    if (slot && slot.serial) {
                        const oldSerial = slot.serial;
                        slot.serial = updateSerialLevel(slot.serial, newLevel);
                        if (slot.serial !== oldSerial) updatedCount++;
                    }
                }
                if (updatedCount > 0) {
                    saveProfileYamlFromMassEditData(data);
                    showSaveStatus('bank-items-status', `✅ Set level ${newLevel} on ${updatedCount} bank item(s).`, true);
                } else {
                    showSaveStatus('bank-items-status', '⚠️ No bank items to update.', false);
                }
            } catch (err) {
                console.error('profileMassChangeLevel:', err);
                showSaveStatus('bank-items-status', `❌ ${err.message}`, false);
            } finally {
                setSaveProcessingState(false);
            }
        }

        function profileUpdateBankSerialLevelsFromSaveCharacter() {
            if (window.saveEditorState.isProcessing) {
                showSaveStatus('bank-items-status', '❌ Wait for the other operation to finish.', false);
                return;
            }
            const saveData = getYamlDataFromTextarea();
            if (!saveData || typeof saveData === 'string' || !saveData.state || !saveData.state.experience) {
                showSaveStatus('bank-items-status', '❌ Load a character save in the Save Editor tab first (character level is read from there).', false);
                return;
            }
            const idx = saveData.state.experience.findIndex((exp) => exp.type === 'Character');
            if (idx === -1) {
                showSaveStatus('bank-items-status', '❌ Character experience not found in loaded save.', false);
                return;
            }
            const level = saveData.state.experience[idx].level || 1;
            setSaveProcessingState(true, 'Profile bank: match save level');
            try {
                const data = loadProfileYamlDataForMassEdit();
                if (!data) {
                    showSaveStatus('bank-items-status', '❌ Could not parse profile YAML.', false);
                    return;
                }
                const bank = ensureProfileBankObject(data);
                let updatedCount = 0;
                for (const slot of Object.values(bank)) {
                    if (slot && slot.serial) {
                        const oldSerial = slot.serial;
                        slot.serial = updateSerialLevel(slot.serial, level);
                        if (slot.serial !== oldSerial) updatedCount++;
                    }
                }
                if (updatedCount > 0) {
                    saveProfileYamlFromMassEditData(data);
                    showSaveStatus('bank-items-status', `✅ Set ${updatedCount} bank item(s) to level ${level} (from loaded save).`, true);
                } else {
                    showSaveStatus('bank-items-status', '⚠️ No bank items to update.', false);
                }
            } catch (err) {
                console.error('profileUpdateBankSerialLevelsFromSaveCharacter:', err);
                showSaveStatus('bank-items-status', `❌ ${err.message}`, false);
            } finally {
                setSaveProcessingState(false);
            }
        }

        async function profileMassRemovePart(statusElementId) {
            if (window.saveEditorState.isProcessing) {
                showSaveStatus(statusElementId, '❌ Cannot remove parts while another process is running.', false);
                return;
            }
            const sid = statusElementId || 'bank-items-status';
            const partInput = document.getElementById('profile-mass-part-input');
            const partPattern = partInput && partInput.value.trim();
            if (!partPattern) {
                showSaveStatus(sid, '❌ Enter a part to remove (e.g. {2} or {247:76}).', false);
                return;
            }
            const partRegex = /^\{(\d+)(?::(\d+))?\}$/;
            const match = partPattern.match(partRegex);
            if (!match) {
                showSaveStatus(sid, '❌ Invalid part format.', false);
                return;
            }
            const typeId = parseInt(match[1], 10);
            const partId = match[2] ? parseInt(match[2], 10) : null;
            setSaveProcessingState(true, 'Profile bank: remove parts');
            try {
                const data = loadProfileYamlDataForMassEdit();
                if (!data) {
                    showSaveStatus(sid, '❌ Could not parse profile YAML.', false);
                    return;
                }
                const bankSlots = ensureProfileBankObject(data);
                const slotKeys = Object.keys(bankSlots);
                if (slotKeys.length === 0) {
                    showSaveStatus(sid, '⚠️ No bank items.', false);
                    return;
                }
                showSaveStatus(sid, `⏳ Processing ${slotKeys.length} bank slot(s)...`, true);
                const serials = [];
                slotKeys.forEach((slotKey) => {
                    const slot = bankSlots[slotKey];
                    if (slot && slot.serial) serials.push(slot.serial);
                });
                if (serials.length === 0) {
                    showSaveStatus(sid, '⚠️ No serials in bank.', false);
                    return;
                }
                const deserializeResults = await deserializeSerialsBulk(serials);
                const deserializedMap = deserializeResults.results || {};
                const modifiedCodes = [];
                const itemsToUpdate = [];
                let removedCount = 0;
                slotKeys.forEach((slotKey) => {
                    const slot = bankSlots[slotKey];
                    if (!slot || !slot.serial) return;
                    const originalSerial = slot.serial;
                    const decodedCode = deserializedMap[originalSerial]?.deserialized || deserializedMap['@' + originalSerial]?.deserialized;
                    if (!decodedCode || !decodedCode.includes('||')) return;
                    const partsMatch = decodedCode.match(/\|\|\s*(.+?)(?:\s*\|)?$/);
                    if (!partsMatch) return;
                    let partsSection = partsMatch[1];
                    let partsChanged = false;
                    if (partId !== null) {
                        const simpleRe = new RegExp(`\\{${typeId}:${partId}\\}`, 'g');
                        if (simpleRe.test(partsSection)) {
                            partsSection = partsSection.replace(new RegExp(`\\{${typeId}:${partId}\\}`, 'g'), '');
                            partsChanged = true;
                        }
                    } else {
                        const typeRe = new RegExp(`\\{${typeId}(?::[^}]+)?\\}`, 'g');
                        if (typeRe.test(partsSection)) {
                            partsSection = partsSection.replace(new RegExp(`\\{${typeId}(?::[^}]+)?\\}`, 'g'), '');
                            partsChanged = true;
                        }
                    }
                    if (partId !== null) {
                        const arrayPattern = new RegExp(`\\{${typeId}:\\[([^\\]]+)\\]\\}`, 'g');
                        partsSection = partsSection.replace(arrayPattern, (m, arrayContents) => {
                            const arrayParts = arrayContents.trim().split(/\s+/).map(n => n.trim()).filter(n => n.length > 0);
                            const partIdStr = partId.toString();
                            const filteredParts = arrayParts.filter(p => p !== partIdStr);
                            if (filteredParts.length === 0) {
                                partsChanged = true;
                                return '';
                            } else if (filteredParts.length === arrayParts.length) {
                                return m;
                            }
                            partsChanged = true;
                            if (filteredParts.length === 1) {
                                return `{${typeId}:${filteredParts[0]}}`;
                            }
                            return `{${typeId}:[${filteredParts.join(' ')}]}`;
                        });
                    }
                    if (partsChanged) {
                        const cleanedParts = partsSection.replace(/\s+/g, ' ').trim();
                        const codeBeforeParts = decodedCode.substring(0, partsMatch.index + 2);
                        const codeAfterParts = decodedCode.substring(partsMatch.index + partsMatch[0].length);
                        const newCode = codeBeforeParts + (cleanedParts ? ' ' + cleanedParts : '') + (codeAfterParts.trim() ? ' ' + codeAfterParts.trim() : '');
                        modifiedCodes.push(newCode);
                        itemsToUpdate.push({ slotKey, slot, newCode });
                        removedCount++;
                    }
                });
                if (removedCount === 0) {
                    showSaveStatus(sid, `⚠️ Part ${partPattern} not found in bank items.`, false);
                    return;
                }
                showSaveStatus(sid, `⏳ Reserializing ${removedCount} item(s)...`, true);
                const normalizedCodes = modifiedCodes.map(code => ensureTrailingPipe(code));
                let serializedResults = [];
                let apiError = null;
                try {
                    const controller = new AbortController();
                    const timeoutId = setTimeout(() => controller.abort(), 120000);
                    const apiBaseUrl = (typeof getLocalApiUrl === 'function') ? getLocalApiUrl() : (typeof API_BASE_URL !== 'undefined' ? API_BASE_URL : 'https://save-editor.be/nicnl/api.php');
                    const response = await fetch(apiBaseUrl, {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({ deserialized_strings: normalizedCodes }),
                        signal: controller.signal,
                    });
                    clearTimeout(timeoutId);
                    if (response.ok) {
                        const respJson = await response.json();
                        if (Array.isArray(respJson) && respJson.length === normalizedCodes.length) {
                            serializedResults = respJson;
                        } else {
                            apiError = 'API returned invalid format';
                        }
                    } else {
                        apiError = await response.text();
                    }
                } catch (error) {
                    apiError = error.message;
                    try {
                        const controller = new AbortController();
                        const timeoutId = setTimeout(() => controller.abort(), 120000);
                        const apiFallbackUrl = (typeof API_FALLBACK_URL !== 'undefined') ? API_FALLBACK_URL : 'https://save-editor.be/nicnl/api.php';
                        const response = await fetch(apiFallbackUrl, {
                            method: 'POST',
                            headers: { 'Content-Type': 'application/json' },
                            body: JSON.stringify({ deserialized_strings: normalizedCodes }),
                            signal: controller.signal,
                        });
                        clearTimeout(timeoutId);
                        if (response.ok) {
                            const respJson = await response.json();
                            if (Array.isArray(respJson) && respJson.length === normalizedCodes.length) {
                                serializedResults = respJson;
                                apiError = null;
                            }
                        }
                    } catch (fallbackError) {
                        apiError = fallbackError.message;
                    }
                }
                if (apiError) throw new Error(String(apiError));
                if (serializedResults.length !== itemsToUpdate.length) {
                    throw new Error('Serialization count mismatch');
                }
                itemsToUpdate.forEach((item, index) => {
                    if (serializedResults[index] && serializedResults[index].trim()) {
                        item.slot.serial = serializedResults[index].trim();
                    }
                });
                saveProfileYamlFromMassEditData(data);
                showSaveStatus(sid, `✅ Removed ${partPattern} from ${removedCount} bank item(s).`, true);
            } catch (err) {
                console.error('profileMassRemovePart:', err);
                showSaveStatus(sid, `❌ ${err.message}`, false);
            } finally {
                setSaveProcessingState(false);
            }
        }

        async function profileMassAddPart(statusElementId) {
            if (window.saveEditorState.isProcessing) {
                showSaveStatus(statusElementId, '❌ Cannot add parts while another process is running.', false);
                return;
            }
            const sid = statusElementId || 'bank-items-status';
            const partInput = document.getElementById('profile-mass-part-add-input');
            const partPattern = partInput && partInput.value.trim();
            if (!partPattern) {
                showSaveStatus(sid, '❌ Enter a part (e.g. {247:76}).', false);
                return;
            }
            const partRegex = /^\{(\d+)(?::(\d+))?\}$/;
            const match = partPattern.match(partRegex);
            if (!match) {
                showSaveStatus(sid, '❌ Invalid part format.', false);
                return;
            }
            const typeId = parseInt(match[1], 10);
            const partId = match[2] ? parseInt(match[2], 10) : null;
            if (partId === null) {
                showSaveStatus(sid, '❌ Use {type:value} to add a part.', false);
                return;
            }
            setSaveProcessingState(true, 'Profile bank: add parts');
            try {
                const data = loadProfileYamlDataForMassEdit();
                if (!data) {
                    showSaveStatus(sid, '❌ Could not parse profile YAML.', false);
                    return;
                }
                const bankSlots = ensureProfileBankObject(data);
                const slotKeys = Object.keys(bankSlots);
                if (slotKeys.length === 0) {
                    showSaveStatus(sid, '⚠️ No bank items.', false);
                    return;
                }
                const serials = [];
                slotKeys.forEach((slotKey) => {
                    const slot = bankSlots[slotKey];
                    if (slot && slot.serial) serials.push(slot.serial);
                });
                if (serials.length === 0) {
                    showSaveStatus(sid, '⚠️ No serials in bank.', false);
                    return;
                }
                const deserializeResults = await deserializeSerialsBulk(serials);
                const deserializedMap = deserializeResults.results || {};
                const modifiedCodes = [];
                const itemsToUpdate = [];
                let addedCount = 0;
                const partIdStr = partId.toString();
                slotKeys.forEach((slotKey) => {
                    const slot = bankSlots[slotKey];
                    if (!slot || !slot.serial) return;
                    const originalSerial = slot.serial;
                    const decodedCode = deserializedMap[originalSerial]?.deserialized || deserializedMap['@' + originalSerial]?.deserialized;
                    if (!decodedCode || !decodedCode.includes('||')) return;
                    const partsMatch = decodedCode.match(/\|\|\s*(.+?)(?:\s*\|)?$/);
                    if (!partsMatch) return;
                    let partsSection = partsMatch[1];
                    let partsChanged = false;
                    const simplePartPattern = new RegExp(`\\{${typeId}:${partId}\\}`, 'g');
                    if (simplePartPattern.test(partsSection)) return;
                    const arrayPattern = new RegExp(`\\{${typeId}:\\[([^\\]]+)\\]\\}`, 'g');
                    const arrayMatches = Array.from(partsSection.matchAll(arrayPattern));
                    let partExistsInArray = false;
                    arrayMatches.forEach((arrayMatch) => {
                        const arrayContents = arrayMatch[1];
                        const arrayParts = arrayContents.trim().split(/\s+/).map(n => n.trim()).filter(n => n.length > 0);
                        if (arrayParts.includes(partIdStr)) partExistsInArray = true;
                    });
                    if (partExistsInArray) return;
                    if (arrayMatches.length > 0) {
                        partsSection = partsSection.replace(arrayPattern, (m, arrayContents) => {
                            const arrayParts = arrayContents.trim().split(/\s+/).map(n => n.trim()).filter(n => n.length > 0);
                            if (!arrayParts.includes(partIdStr)) {
                                arrayParts.push(partIdStr);
                                arrayParts.sort((a, b) => parseInt(a, 10) - parseInt(b, 10));
                                partsChanged = true;
                                return `{${typeId}:[${arrayParts.join(' ')}]}`;
                            }
                            return m;
                        });
                    } else {
                        const trimmedParts = partsSection.trim();
                        partsSection = trimmedParts ? trimmedParts + ' ' + partPattern : partPattern;
                        partsChanged = true;
                    }
                    if (partsChanged) {
                        const cleanedParts = partsSection.replace(/\s+/g, ' ').trim();
                        const codeBeforeParts = decodedCode.substring(0, partsMatch.index + 2);
                        const codeAfterParts = decodedCode.substring(partsMatch.index + partsMatch[0].length);
                        const newCode = codeBeforeParts + (cleanedParts ? ' ' + cleanedParts : '') + (codeAfterParts.trim() ? ' ' + codeAfterParts.trim() : '');
                        modifiedCodes.push(newCode);
                        itemsToUpdate.push({ slotKey, slot, newCode });
                        addedCount++;
                    }
                });
                if (addedCount === 0) {
                    showSaveStatus(sid, `⚠️ Part ${partPattern} already present or no items modified.`, false);
                    return;
                }
                const normalizedCodes = modifiedCodes.map(code => ensureTrailingPipe(code));
                let serializedResults = [];
                let apiError = null;
                try {
                    const controller = new AbortController();
                    const timeoutId = setTimeout(() => controller.abort(), 120000);
                    const apiBaseUrl = (typeof getLocalApiUrl === 'function') ? getLocalApiUrl() : (typeof API_BASE_URL !== 'undefined' ? API_BASE_URL : 'https://save-editor.be/nicnl/api.php');
                    const response = await fetch(apiBaseUrl, {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({ deserialized_strings: normalizedCodes }),
                        signal: controller.signal,
                    });
                    clearTimeout(timeoutId);
                    if (response.ok) {
                        const respJson = await response.json();
                        if (Array.isArray(respJson) && respJson.length === normalizedCodes.length) {
                            serializedResults = respJson;
                        } else {
                            apiError = 'API returned invalid format';
                        }
                    } else {
                        apiError = await response.text();
                    }
                } catch (error) {
                    apiError = error.message;
                    try {
                        const controller = new AbortController();
                        const timeoutId = setTimeout(() => controller.abort(), 120000);
                        const apiFallbackUrl = (typeof API_FALLBACK_URL !== 'undefined') ? API_FALLBACK_URL : 'https://save-editor.be/nicnl/api.php';
                        const response = await fetch(apiFallbackUrl, {
                            method: 'POST',
                            headers: { 'Content-Type': 'application/json' },
                            body: JSON.stringify({ deserialized_strings: normalizedCodes }),
                            signal: controller.signal,
                        });
                        clearTimeout(timeoutId);
                        if (response.ok) {
                            const respJson = await response.json();
                            if (Array.isArray(respJson) && respJson.length === normalizedCodes.length) {
                                serializedResults = respJson;
                                apiError = null;
                            }
                        }
                    } catch (fallbackError) {
                        apiError = fallbackError.message;
                    }
                }
                if (apiError) throw new Error(String(apiError));
                if (serializedResults.length !== itemsToUpdate.length) {
                    throw new Error('Serialization count mismatch');
                }
                itemsToUpdate.forEach((item, index) => {
                    if (serializedResults[index] && serializedResults[index].trim()) {
                        item.slot.serial = serializedResults[index].trim();
                    }
                });
                saveProfileYamlFromMassEditData(data);
                showSaveStatus(sid, `✅ Added ${partPattern} to ${addedCount} bank item(s).`, true);
            } catch (err) {
                console.error('profileMassAddPart:', err);
                showSaveStatus(sid, `❌ ${err.message}`, false);
            } finally {
                setSaveProcessingState(false);
            }
        }

        async function profileMassChangeStateFlags() {
            if (window.saveEditorState.isProcessing) {
                showSaveStatus('bank-items-status', '❌ Cannot change flags while another process is running.', false);
                return;
            }
            const stateFlagSelect = document.getElementById('profile-mass-state-flag-select');
            if (!stateFlagSelect) {
                showSaveStatus('bank-items-status', '❌ State flag selector not found.', false);
                return;
            }
            const newStateFlag = stateFlagSelect.value;
            setSaveProcessingState(true, 'Profile bank: state flags');
            try {
                const data = loadProfileYamlDataForMassEdit();
                if (!data) {
                    showSaveStatus('bank-items-status', '❌ Could not parse profile YAML.', false);
                    return;
                }
                const bank = ensureProfileBankObject(data);
                let updatedCount = 0;
                for (const slot of Object.values(bank)) {
                    if (!slot || !slot.serial) continue;
                    if (newStateFlag === '') {
                        if (slot.state_flags !== undefined && slot.state_flags !== null) {
                            delete slot.state_flags;
                            updatedCount++;
                        }
                    } else {
                        const oldStateFlag = slot.state_flags;
                        slot.state_flags = parseInt(newStateFlag, 10);
                        if (slot.state_flags !== oldStateFlag) updatedCount++;
                    }
                }
                if (updatedCount > 0) {
                    const flagLabel = stateFlagSelect.options[stateFlagSelect.selectedIndex].text;
                    saveProfileYamlFromMassEditData(data);
                    showSaveStatus('bank-items-status', `✅ Updated state flags (${flagLabel}) on ${updatedCount} bank item(s).`, true);
                } else {
                    showSaveStatus('bank-items-status', '⚠️ No bank items to update.', false);
                }
            } catch (err) {
                console.error('profileMassChangeStateFlags:', err);
                showSaveStatus('bank-items-status', `❌ ${err.message}`, false);
            } finally {
                setSaveProcessingState(false);
            }
        }

