        async function profileQuickRemoveRainbowVomit() {
            if (window.saveEditorState.isProcessing) {
                showSaveStatus('profile-quick-remove-status', '❌ Another process is running.', false);
                return;
            }
            setSaveProcessingState(true, 'Profile bank: Rainbow Vomit');
            try {
                const data = loadProfileYamlDataForMassEdit();
                if (!data) {
                    showSaveStatus('profile-quick-remove-status', '❌ Could not parse profile YAML.', false);
                    return;
                }
                const bankSlots = ensureProfileBankObject(data);
                const slotKeys = Object.keys(bankSlots);
                if (slotKeys.length === 0) {
                    showSaveStatus('profile-quick-remove-status', '⚠️ No bank items.', false);
                    return;
                }
                const serials = [];
                slotKeys.forEach((slotKey) => {
                    const slot = bankSlots[slotKey];
                    if (slot && slot.serial) serials.push(slot.serial);
                });
                if (serials.length === 0) {
                    showSaveStatus('profile-quick-remove-status', '⚠️ No serials in bank.', false);
                    return;
                }
                showSaveStatus('profile-quick-remove-status', `⏳ Deserializing ${serials.length} item(s)...`, true);
                const deserializeResults = await deserializeSerialsBulk(serials);
                const deserializedMap = deserializeResults.results || {};
                const rainbowVomitPartIds = new Set();
                if (window.gameData && window.gameData.parts) {
                    window.gameData.parts.forEach(part => {
                        const spawnCode = (part.spawn_code || part.spawnCode || '').toLowerCase();
                        if (spawnCode.includes('rainbowvomit')) {
                            const idMatch = (part.id || '').match(/^(\d+):(\d+)$/);
                            if (idMatch) {
                                rainbowVomitPartIds.add(`${idMatch[1]}:${idMatch[2]}`);
                            }
                        }
                    });
                }
                ['9:1', '9:16', '9:71', '9:72', '9:73', '9:74', '9:75', '9:76', '9:77', '9:84', '9:86'].forEach(id => rainbowVomitPartIds.add(id));
                if (rainbowVomitPartIds.size === 0) {
                    showSaveStatus('profile-quick-remove-status', '⚠️ No Rainbow Vomit part data.', false);
                    return;
                }
                const modifiedCodes = [];
                const itemsToUpdate = [];
                let removedCount = 0;
                slotKeys.forEach((slotKey) => {
                    const slot = bankSlots[slotKey];
                    if (!slot || !slot.serial) return;
                    const originalSerial = slot.serial;
                    const decodedCode = deserializedMap[originalSerial]?.deserialized || deserializedMap['@' + originalSerial]?.deserialized;
                    if (!decodedCode || !decodedCode.includes('||')) return;
                    const partsMatch = decodedCode.match(/\|\|\s*(.+?)(?:\s*\|)?$/);
                    if (!partsMatch) return;
                    let partsSection = partsMatch[1];
                    let partsChanged = false;
                    rainbowVomitPartIds.forEach(partIdStr => {
                        const [tid, pid] = partIdStr.split(':');
                        if (new RegExp(`\\{${tid}:${pid}\\}`).test(partsSection)) {
                            partsSection = partsSection.replace(new RegExp(`\\{${tid}:${pid}\\}`, 'g'), '');
                            partsChanged = true;
                        }
                        const arrayPattern = new RegExp(`\\{${tid}:\\[([^\\]]+)\\]\\}`, 'g');
                        partsSection = partsSection.replace(arrayPattern, (m, arrayContents) => {
                            const arrayParts = arrayContents.trim().split(/\s+/).map(n => n.trim()).filter(n => n.length > 0);
                            const filteredParts = arrayParts.filter(p => p !== pid);
                            if (filteredParts.length === 0) {
                                partsChanged = true;
                                return '';
                            } else if (filteredParts.length === arrayParts.length) {
                                return m;
                            }
                            partsChanged = true;
                            if (filteredParts.length === 1) {
                                return `{${tid}:${filteredParts[0]}}`;
                            }
                            return `{${tid}:[${filteredParts.join(' ')}]}`;
                        });
                    });
                    if (partsChanged) {
                        const cleanedParts = partsSection.replace(/\s+/g, ' ').trim();
                        const codeBeforeParts = decodedCode.substring(0, partsMatch.index + 2);
                        const codeAfterParts = decodedCode.substring(partsMatch.index + partsMatch[0].length);
                        const newCode = codeBeforeParts + (cleanedParts ? ' ' + cleanedParts : '') + (codeAfterParts.trim() ? ' ' + codeAfterParts.trim() : '');
                        modifiedCodes.push(newCode);
                        itemsToUpdate.push({ slotKey, slot, newCode });
                        removedCount++;
                    }
                });
                if (removedCount === 0) {
                    showSaveStatus('profile-quick-remove-status', '⚠️ No Rainbow Vomit parts found in bank.', false);
                    return;
                }
                const normalizedCodes = modifiedCodes.map(code => ensureTrailingPipe(code));
                let serializedResults = [];
                let apiError = null;
                try {
                    const controller = new AbortController();
                    const timeoutId = setTimeout(() => controller.abort(), 120000);
                    const apiBaseUrl = (typeof getLocalApiUrl === 'function') ? getLocalApiUrl() : (typeof API_BASE_URL !== 'undefined' ? API_BASE_URL : 'https://save-editor.be/nicnl/api.php');
                    const response = await fetch(apiBaseUrl, {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({ deserialized_strings: normalizedCodes }),
                        signal: controller.signal,
                    });
                    clearTimeout(timeoutId);
                    if (response.ok) {
                        const respJson = await response.json();
                        if (Array.isArray(respJson) && respJson.length === normalizedCodes.length) {
                            serializedResults = respJson;
                        } else {
                            apiError = 'Invalid API response';
                        }
                    } else {
                        apiError = await response.text();
                    }
                } catch (error) {
                    apiError = error.message;
                    try {
                        const controller = new AbortController();
                        const timeoutId = setTimeout(() => controller.abort(), 120000);
                        const apiFallbackUrl = (typeof API_FALLBACK_URL !== 'undefined') ? API_FALLBACK_URL : 'https://save-editor.be/nicnl/api.php';
                        const response = await fetch(apiFallbackUrl, {
                            method: 'POST',
                            headers: { 'Content-Type': 'application/json' },
                            body: JSON.stringify({ deserialized_strings: normalizedCodes }),
                            signal: controller.signal,
                        });
                        clearTimeout(timeoutId);
                        if (response.ok) {
                            const respJson = await response.json();
                            if (Array.isArray(respJson) && respJson.length === normalizedCodes.length) {
                                serializedResults = respJson;
                                apiError = null;
                            }
                        }
                    } catch (fallbackError) {
                        apiError = fallbackError.message;
                    }
                }
                if (apiError) throw new Error(String(apiError));
                if (serializedResults.length !== itemsToUpdate.length) {
                    throw new Error('Serialization count mismatch');
                }
                itemsToUpdate.forEach((item, index) => {
                    if (serializedResults[index] && serializedResults[index].trim()) {
                        item.slot.serial = serializedResults[index].trim();
                    }
                });
                saveProfileYamlFromMassEditData(data);
                showSaveStatus('profile-quick-remove-status', `✅ Removed Rainbow Vomit from ${removedCount} bank item(s).`, true);
            } catch (err) {
                console.error('profileQuickRemoveRainbowVomit:', err);
                showSaveStatus('profile-quick-remove-status', `❌ ${err.message}`, false);
            } finally {
                setSaveProcessingState(false);
            }
        }

        function copySaveYamlToClipboard() {
            const yamlContent = typeof getYamlTextareaValue === 'function'
                ? getYamlTextareaValue()
                : '';

            if (!yamlContent || !yamlContent.trim()) {
                showSaveStatus('save-encrypt-status', 'No YAML content to copy.', false);
                return;
            }

            const markCopied = function() {
                showSaveStatus('save-encrypt-status', 'YAML copied to clipboard!', true);
                if (typeof window.trackEvent === 'function') {
                    window.trackEvent('copy_clipboard', { source: 'button' });
                }
            };

            const fallbackCopy = function() {
                const fallbackTextarea = document.createElement('textarea');
                fallbackTextarea.value = yamlContent;
                fallbackTextarea.setAttribute('readonly', 'readonly');
                fallbackTextarea.style.position = 'fixed';
                fallbackTextarea.style.left = '-9999px';
                fallbackTextarea.style.top = '0';
                document.body.appendChild(fallbackTextarea);
                fallbackTextarea.select();
                document.execCommand('copy');
                document.body.removeChild(fallbackTextarea);
                markCopied();
            };

            if (navigator.clipboard && typeof navigator.clipboard.writeText === 'function') {
                navigator.clipboard.writeText(yamlContent)
                    .then(markCopied)
                    .catch(fallbackCopy);
            } else {
                fallbackCopy();
            }
            return;

            const textarea = document.getElementById('save-yaml-textarea');
            if (textarea) {
                textarea.select();
                document.execCommand('copy');
                showSaveStatus('save-encrypt-status', '✅ YAML copied to clipboard!', true);
                // Track clipboard copy
                if (typeof window.trackEvent === 'function') {
                    window.trackEvent('copy_clipboard', { source: 'button' });
                }
            }
        }

        function downloadYamlFile() {
            const yamlContent = getYamlTextareaValue();
            if (!yamlContent || !yamlContent.trim()) {
                showSaveStatus('save-encrypt-status', '❌ No YAML content to download.', false);
                return;
            }
            const blob = new Blob([yamlContent], { type: 'text/yaml' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            
            // Use original filename if available, otherwise default
            const originalFileName = window.saveEditorState.originalFileName || 'save';
            const fileNameWithoutExt = originalFileName.replace(/\.(sav|yaml|yml)$/i, '');
            a.download = `${fileNameWithoutExt}.yaml`;
            
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
            
            showSaveStatus('save-encrypt-status', `✅ YAML file downloaded as "${a.download}"!`, true);
        }

